import{_ as a,c as i,o as t,ak as o,ao as n}from"./chunks/framework.B0TWM2iJ.js";const m=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-116-0.md","filePath":"aireblock-releases/aireglu-v1-116-0.md","lastUpdated":1775826979000}'),s={name:"aireblock-releases/aireglu-v1-116-0.md"};function r(l,e,c,d,p,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+n+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.116.0<br><strong>Release Date:</strong> 21st April 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Automatic AireForms Schema Import for Endpoints (GLU-2873)</li><li>Connect AireGlu Endpoints to AI Assistants via MCP (GLU-2904)</li><li>Tenant-Wide Client Credential Connections for HTTP Request Authentication (GLU-2998)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Unsaved Changes Warning in Endpoint Editor (GLU-2813)</li><li>Improved Auto-Generated Schema Validation (GLU-2945)</li><li>Expanded Retry Support for Endpoint-to-Endpoint Calls (GLU-2967)</li><li>Usage Data Table Refresh Button (GLU-2915)</li><li>Retry Activity in Metrics (GLU-3007)</li><li>Narrowed Retry Conditions to Specific Exceptions (GLU-3024)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Job Re-activation Runs Immediately (GLU-2955)</li><li>JSON Editor Container Overflow on JWT Headers (GLU-2900)</li><li>Config Assistant Broken After BFF Migration (GLU-2996)</li><li>Improved Error Message for Empty XML Schema Save Failure (GLU-3036)</li><li>Search Close Opens All Groups (GLU-3016)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="automatic-aireforms-schema-import-for-endpoints-glu-2873" tabindex="-1">Automatic AireForms Schema Import for Endpoints (GLU-2873) <a class="header-anchor" href="#automatic-aireforms-schema-import-for-endpoints-glu-2873" aria-label="Permalink to “Automatic AireForms Schema Import for Endpoints (GLU-2873)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The endpoint editor can now automatically pull in AireForms schemas as the input schema for an endpoint, removing the need to define or copy schemas manually.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When configuring an endpoint that receives data from an AireForm, you can now import the form&#39;s schema directly into the editor with a single action, saving time and reducing the risk of mismatches between your form and endpoint configuration.</p></div><h4 id="connect-aireglu-endpoints-to-ai-assistants-via-mcp-glu-2904" tabindex="-1">Connect AireGlu Endpoints to AI Assistants via MCP (GLU-2904) <a class="header-anchor" href="#connect-aireglu-endpoints-to-ai-assistants-via-mcp-glu-2904" aria-label="Permalink to “Connect AireGlu Endpoints to AI Assistants via MCP (GLU-2904)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireGlu endpoints can now be connected to AI assistants using the Model Context Protocol (MCP), enabling AI tools to discover and invoke endpoints as part of an agentic workflow.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now expose your AireGlu endpoints to AI assistants, allowing them to be called as tools within AI-driven processes — opening up new possibilities for automation and intelligent workflows across your organisation.</p></div><h4 id="tenant-wide-client-credential-connections-for-http-request-authentication-glu-2998" tabindex="-1">Tenant-Wide Client Credential Connections for HTTP Request Authentication (GLU-2998) <a class="header-anchor" href="#tenant-wide-client-credential-connections-for-http-request-authentication-glu-2998" aria-label="Permalink to “Tenant-Wide Client Credential Connections for HTTP Request Authentication (GLU-2998)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Tenant-wide client credential connections can now be configured and used to authenticate HTTP requests within endpoints, providing a centralised and reusable approach to securing outbound API calls.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now set up a shared client credential connection once at the tenant level and apply it to HTTP requests across multiple endpoints, reducing repetitive configuration and making it easier to manage authentication credentials in one place.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="unsaved-changes-warning-in-endpoint-editor-glu-2813" tabindex="-1">Unsaved Changes Warning in Endpoint Editor (GLU-2813) <a class="header-anchor" href="#unsaved-changes-warning-in-endpoint-editor-glu-2813" aria-label="Permalink to “Unsaved Changes Warning in Endpoint Editor (GLU-2813)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The endpoint editor now displays a warning when navigating away with unsaved changes, preventing accidental loss of work.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll be prompted before leaving the editor if you have unsaved changes, giving you the chance to save or discard before moving on.</p></div><h4 id="improved-auto-generated-schema-validation-glu-2945" tabindex="-1">Improved Auto-Generated Schema Validation (GLU-2945) <a class="header-anchor" href="#improved-auto-generated-schema-validation-glu-2945" aria-label="Permalink to “Improved Auto-Generated Schema Validation (GLU-2945)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The minimum items requirement has been removed from automatically generated JSON schemas in the endpoint editor, preventing schemas from incorrectly failing their own validation.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Auto-generated schemas will now validate correctly out of the box, reducing configuration errors when setting up endpoints that use automatically derived input schemas.</p></div><h4 id="expanded-retry-support-for-endpoint-to-endpoint-calls-glu-2967" tabindex="-1">Expanded Retry Support for Endpoint-to-Endpoint Calls (GLU-2967) <a class="header-anchor" href="#expanded-retry-support-for-endpoint-to-endpoint-calls-glu-2967" aria-label="Permalink to “Expanded Retry Support for Endpoint-to-Endpoint Calls (GLU-2967)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Retry logic has been extended to cover calls made from one AireGlu endpoint to another, improving resilience when transient failures occur between endpoints.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>AireGlu will now automatically retry failed endpoint-to-endpoint calls, reducing the impact of temporary disruptions and making your integrations more reliable.</p></div><h4 id="usage-data-table-refresh-button-glu-2915" tabindex="-1">Usage Data Table Refresh Button (GLU-2915) <a class="header-anchor" href="#usage-data-table-refresh-button-glu-2915" aria-label="Permalink to “Usage Data Table Refresh Button (GLU-2915)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A refresh button has been added to the usage data table in the metrics view, allowing the latest data to be loaded without navigating away from the page.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now reload your usage data on demand with a single click, giving you up-to-date information without having to leave and return to the metrics view.</p></div><h4 id="retry-activity-in-metrics-glu-3007" tabindex="-1">Retry Activity in Metrics (GLU-3007) <a class="header-anchor" href="#retry-activity-in-metrics-glu-3007" aria-label="Permalink to “Retry Activity in Metrics (GLU-3007)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Retry attempts are now recorded and displayed within the metrics view, providing visibility into how often tasks are retried and their outcomes.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now see retry activity alongside your other metrics, helping you identify unreliable integrations and understand how often automatic retries are occurring.</p></div><h4 id="narrowed-retry-conditions-to-specific-exceptions-glu-3024" tabindex="-1">Narrowed Retry Conditions to Specific Exceptions (GLU-3024) <a class="header-anchor" href="#narrowed-retry-conditions-to-specific-exceptions-glu-3024" aria-label="Permalink to “Narrowed Retry Conditions to Specific Exceptions (GLU-3024)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The retry mechanism has been updated to trigger only on specific, well-defined HTTP exceptions rather than broadly on any failure, reducing unnecessary retries and improving predictability.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Retries will now only occur when genuinely appropriate, making the behaviour of your integrations more consistent and easier to reason about.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="job-re-activation-runs-immediately-glu-2955" tabindex="-1">Job Re-activation Runs Immediately (GLU-2955) <a class="header-anchor" href="#job-re-activation-runs-immediately-glu-2955" aria-label="Permalink to “Job Re-activation Runs Immediately (GLU-2955)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where re-activating a scheduled job would cause it to run immediately if it had run previously, rather than waiting for its next scheduled time.</p></div><h4 id="json-editor-container-overflow-on-jwt-headers-glu-2900" tabindex="-1">JSON Editor Container Overflow on JWT Headers (GLU-2900) <a class="header-anchor" href="#json-editor-container-overflow-on-jwt-headers-glu-2900" aria-label="Permalink to “JSON Editor Container Overflow on JWT Headers (GLU-2900)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where the JSON editor would overflow its container when JWT headers were displayed, causing layout problems in the endpoint editor.</p></div><h4 id="config-assistant-broken-after-bff-migration-glu-2996" tabindex="-1">Config Assistant Broken After BFF Migration (GLU-2996) <a class="header-anchor" href="#config-assistant-broken-after-bff-migration-glu-2996" aria-label="Permalink to “Config Assistant Broken After BFF Migration (GLU-2996)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where the endpoint editor config assistant stopped functioning following the BFF (Backend for Frontend) migration, restoring full assistant functionality.</p></div><h4 id="improved-error-message-for-empty-xml-schema-save-failure-glu-3036" tabindex="-1">Improved Error Message for Empty XML Schema Save Failure (GLU-3036) <a class="header-anchor" href="#improved-error-message-for-empty-xml-schema-save-failure-glu-3036" aria-label="Permalink to “Improved Error Message for Empty XML Schema Save Failure (GLU-3036)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Improved the error message shown when an endpoint with an empty or invalid XML schema fails to save, making it clearer to the user that the save was unsuccessful.</p></div><h4 id="search-close-opens-all-groups-glu-3016" tabindex="-1">Search Close Opens All Groups (GLU-3016) <a class="header-anchor" href="#search-close-opens-all-groups-glu-3016" aria-label="Permalink to “Search Close Opens All Groups (GLU-3016)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a bug where closing a search in the endpoints list would unexpectedly expand all collapsed groups, disrupting the user&#39;s view.</p></div>',54)])])}const g=a(s,[["render",r]]);export{m as __pageData,g as default};
